text:
{
 "setup": [
  {
   "id": "beat:storm-season",
   "summary": "Storm season on the Stilt Light. Maren tends the lamp alone; below the waterline, something turns over in its sleep.",
   "effect": "advances",
   "entities": [
    "character:keeper",
    "location:lighthouse"
   ]
  }
 ],
 "scaffolds": [
  {
   "dilemma": "dilemma:bargain",
   "pre_commit": [
    {
     "id": "beat:the-ledger",
     "summary": "Maren re-reads her grandmother's ledger: the bargain's terms, the price already paid, the line left blank for her.",
     "effect": "advances",
     "entities": [
      "character:keeper",
      "location:lighthouse"
     ]
    },
    {
     "id": "beat:the-tremor",
     "summary": "The sea pulls back from the stilts and the lamp gutters blue; the sleeper turns, and the bargain begins to come due.",
     "effect": "reveals",
     "entities": [
      "character:keeper",
      "character:sleeper",
      "location:lighthouse"
     ]
    }
   ],
   "paths": [
    {
     "path": "path:keep",
     "commit": {
      "id": "beat:keep-commit",
      "summary": "At dawn Maren sends the ship away and trims the wick. The bargain holds, and the blank line gets her name.",
      "effect": "advances",
      "entities": [
       "character:keeper",
       "location:lighthouse"
      ]
     },
     "post_commit": [
      {
       "id": "beat:keep-price",
       "summary": "The sea settles like a dog by a fire. The coast never learns what it was spared, which is the shape of the price.",
       "effect": "advances",
       "entities": [
        "character:keeper",
        "character:sleeper"
       ]
      },
      {
       "id": "beat:the-long-watch",
       "summary": "Ending: the coast sleeps because Maren does not. Some nights a corrected chart arrives by post, in a tidy hand.",
       "effect": "advances",
       "entities": [
        "character:keeper",
        "location:lighthouse"
       ],
       "is_ending": true
      }
     ]
    },
    {
     "path": "path:break",
     "commit": {
      "id": "beat:break-commit",
      "summary": "At dawn Maren caps the lamp and steps aboard; behind her, for the first time in three generations, the Stilt Light goes dark.",
      "effect": "advances",
      "entities": [
       "character:keeper",
       "location:lighthouse"
      ]
     },
     "post_commit": [
      {
       "id": "beat:break-price",
       "summary": "The sea does not settle. Something follows the ship the way a storm follows heat, and the shoals empty of birds.",
       "effect": "advances",
       "entities": [
        "character:keeper",
        "character:sleeper"
       ]
      },
      {
       "id": "beat:the-wide-water",
       "summary": "Ending: Maren is free, and the deep is awake. She keeps no lamp now, but she still wakes at the hour of the trimming.",
       "effect": "advances",
       "entities": [
        "character:keeper",
        "character:sleeper"
       ],
       "is_ending": true
      }
     ]
    }
   ]
  },
  {
   "dilemma": "dilemma:truth",
   "pre_commit": [
    {
     "id": "beat:elias-arrives",
     "summary": "Elias Wren lands with his chart cases, hired to map the shoals \u2014 and full of questions about the light's odd schedule.",
     "effect": "advances",
     "entities": [
      "character:keeper",
      "character:cartographer"
     ]
    },
    {
     "id": "beat:false-soundings",
     "summary": "Elias's soundings keep coming back wrong; he shows Maren depths that should not exist. She must answer him with something.",
     "effect": "complicates",
     "entities": [
      "character:keeper",
      "character:cartographer",
      "character:sleeper"
     ]
    }
   ],
   "paths": [
    {
     "path": "path:tell",
     "commit": {
      "id": "beat:tell-commit",
      "summary": "Maren takes Elias down to the lamp room at slack tide and tells him what the light holds.",
      "effect": "advances",
      "entities": [
       "character:keeper",
       "character:cartographer",
       "location:lighthouse"
      ]
     },
     "post_commit": [
      {
       "id": "beat:tell-payoff",
       "summary": "Elias stays. He learns the lamp's rhythm and stands the night watch beside her, chart abandoned on the table.",
       "effect": "advances",
       "entities": [
        "character:keeper",
        "character:cartographer"
       ]
      }
     ]
    },
    {
     "path": "path:hide",
     "commit": {
      "id": "beat:hide-commit",
      "summary": "Maren laughs off the soundings \u2014 bad instruments, worse weather \u2014 and burns the ledger page he nearly saw.",
      "effect": "advances",
      "entities": [
       "character:keeper",
       "character:cartographer"
      ]
     },
     "post_commit": [
      {
       "id": "beat:hide-payoff",
       "summary": "Elias grows quiet and watchful; the lie sits between them at every shared meal, patient as the thing below.",
       "effect": "complicates",
       "entities": [
        "character:keeper",
        "character:cartographer"
       ]
      }
     ]
    }
   ]
  }
 ]
}
